msg.url = env.get('CLOUD_BRIDGE_URL');
msg.headers = {
  'Authorization': 'Bearer ' + env.get('CLOUD_DEVICE_TOKEN'),
  'Content-Type': 'application/json'
};
if (msg.payload && !msg.payload.ts) msg.payload.ts = new Date().toISOString();
if (msg.payload && !msg.payload.device) msg.payload.device = env.get('DEFAULT_DEVICE_LABEL');
return msg;

